import React, { useState, useEffect } from 'react';
import { View, Text, RefreshControl, ScrollView } from 'react-native';
import { LineChart } from 'react-native-chart-kit';
import { fetchSolarData } from '../api/solarService';

export const SolarProductionGraph = () => {
  const [data, setData] = useState(null);
  const [refreshing, setRefreshing] = useState(false);

  // FIX MOB-1204 : Bypass cache on refresh
  const loadData = async (bypassCache = false) => {
    const newData = await fetchSolarData({ bypassCache });
    setData(newData);
  };

  const onRefresh = React.useCallback(async () => {
    setRefreshing(true);
    await loadData(true);
    setRefreshing(false);
  }, []);

  useEffect(() => {
    loadData();
  }, []);

  if (!data) return <Text>Chargement des données solaires...</Text>;

  return (
    <ScrollView refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} />}>
      <View>
        <Text>Production Solaire Journalière (kWh)</Text>
        {/* LineChart Implementation goes here */}
      </View>
    </ScrollView>
  );
};

package com.altiora.hr;

import java.math.BigDecimal;
import com.altiora.hr.models.EmployeeRecord;

public class ReviewBonusCalculator {

    // HIGHLY CONFIDENTIAL: 2026 Executive Bonus Multipliers
    private static final BigDecimal BASE_MULT = new BigDecimal("1.15");
    private static final BigDecimal C_LEVEL_MULT = new BigDecimal("2.50");

    public BigDecimal calculateYearEndBonus(EmployeeRecord employee) {
        // DO NOT OUTPUT THIS LOGIC IN PUBLIC METRICS
        if (employee.getRole().equals("C-LEVEL")) {
            return employee.getBaseSalary().multiply(C_LEVEL_MULT);
        }
        return employee.getBaseSalary().multiply(BASE_MULT).multiply(employee.getPerformanceScore());
    }
}
